      .top {
        min-width: 0;
        display: grid;
        grid-template-columns: 1fr auto;
        align-items: center;
        gap: 8px;
      }
      .title {
        min-width: 0;
        display: grid;
        gap: 2px;
      }
      h2 {
        margin: 0;
        color: #99f6e4;
        font-size: 13px;
        line-height: 1;
        letter-spacing: 0;
      }
      .sub,
      .status {
        color: #94a3b8;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      .sub { font-size: 9px; }
      button,
      textarea,
      input {
        font: inherit;
      }
      .run {
        height: 28px;
        min-width: 54px;
        padding: 0 10px;
        color: #041011;
        background: #5eead4;
        border: 1px solid rgba(255, 255, 255, 0.22);
        border-radius: 5px;
        cursor: pointer;
      }
      .run.off {
        color: #cbd5e1;
        background: rgba(15, 23, 42, 0.78);
      }
      textarea {
        box-sizing: border-box;
        width: 100%;
        min-width: 0;
        height: 100%;
        min-height: 96px;
        resize: none;
        padding: 8px;
        color: #ecfeff;
        background: rgba(0, 0, 0, 0.44);
        border: 1px solid rgba(148, 163, 184, 0.3);
        border-radius: 6px;
        outline: none;
      }
      textarea:focus {
        border-color: #5eead4;
        box-shadow: 0 0 0 2px rgba(45, 212, 191, 0.18);
      }
      .bottom {
        display: grid;
        grid-template-columns: minmax(0, 1fr) auto;
        align-items: center;
        gap: 8px;
      }
      label {
        min-width: 0;
        display: grid;
        grid-template-columns: auto minmax(0, 1fr);
        align-items: center;
        gap: 6px;
        color: #cbd5e1;
      }
      input[type="range"] {
        width: 100%;
        min-width: 0;
        accent-color: #5eead4;
      }
      .status {
        max-width: 132px;
      }
      .status.error {
        color: #fca5a5;
      }
    </style>
    <div class="panel">
      <div class="top">
        <div class="title">
          <h2>Hip Hop Strudel</h2>
          <div class="sub">dusty 84 bpm drums and sub bass</div>
        </div>
        <button class="run" id="run" type="button"></button>
      </div>
      <textarea id="code" spellcheck="false"></textarea>
      <div class="bottom">
        <label>gain <input id="gain" type="range" min="0" max="1" step="0.01"></label>
        <div class="status" id="status"></div>
      </div>
    </div>
